import React, { useEffect, useState } from "react";
import {
  Box,
  Card,
  CardContent,
  CardMedia,
  Divider,
  Link,
  Stack,
  Typography,
} from "@mui/material";
import { Link as RouterLink, useParams } from "react-router-dom";

import "./styles.css";
import fetchModel from "../../lib/fetchModelData";

import ouster from "../../images/ouster.jpg";
import malcolm1 from "../../images/malcolm1.jpg";
import malcolm2 from "../../images/malcolm2.jpg";
import ripley1 from "../../images/ripley1.jpg";
import ripley2 from "../../images/ripley2.jpg";
import kenobi1 from "../../images/kenobi1.jpg";
import kenobi2 from "../../images/kenobi2.jpg";
import kenobi3 from "../../images/kenobi3.jpg";
import kenobi4 from "../../images/kenobi4.jpg";
import took1 from "../../images/took1.jpg";
import took2 from "../../images/took2.jpg";
import ludgate1 from "../../images/ludgate1.jpg";

const PHOTO_SRC_BY_FILE = {
  "ouster.jpg": ouster,
  "malcolm1.jpg": malcolm1,
  "malcolm2.jpg": malcolm2,
  "ripley1.jpg": ripley1,
  "ripley2.jpg": ripley2,
  "kenobi1.jpg": kenobi1,
  "kenobi2.jpg": kenobi2,
  "kenobi3.jpg": kenobi3,
  "kenobi4.jpg": kenobi4,
  "took1.jpg": took1,
  "took2.jpg": took2,
  "ludgate1.jpg": ludgate1,
};

function parseModelDate(value) {
  if (value == null) return null;
  if (value instanceof Date) {
    return Number.isNaN(value.getTime()) ? null : value;
  }
  const s = String(value);
  const normalized = s.includes("T") ? s : s.replace(" ", "T");
  const d = new Date(normalized);
  return Number.isNaN(d.getTime()) ? null : d;
}

function formatFriendlyDateTime(value) {
  const d = parseModelDate(value);
  if (!d) return "Unknown date";
  return d.toLocaleString(undefined, {
    dateStyle: "long",
    timeStyle: "short",
  });
}

/**
 * Define UserPhotos, a React component of Project 4.
 */
function UserPhotos() {
  const { userId } = useParams();
  const [user, setUser] = useState(null);
  const [photos, setPhotos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [userData, photosData] = await Promise.all([
          fetchModel(`/user/${userId}`),
          fetchModel(`/photosOfUser/${userId}`)
        ]);
        setUser(userData);
        setPhotos(photosData);
        setLoading(false);
      } catch (error) {
        console.error("Error fetching data:", error);
        setLoading(false);
      }
    };
    fetchData();
  }, [userId]);

  if (loading) {
    return <Typography variant="body1">Loading...</Typography>;
  }

  if (!user) {
    return (
      <Typography variant="body1" color="text.secondary">
        User not found.
      </Typography>
    );
  }

  const ownerName = `${user.first_name} ${user.last_name}`;

  return (
    <Stack spacing={3} className="user-photos">
      <Typography variant="h5" component="h1">
        Photos of {ownerName}
      </Typography>
      {photos.length === 0 ? (
        <Typography variant="body2" color="text.secondary">
          No photos yet.
        </Typography>
      ) : (
        photos.map((photo) => {
          const src = PHOTO_SRC_BY_FILE[photo.file_name];
          const comments = [...(photo.comments || [])].sort((a, b) => {
            const da = parseModelDate(a.date_time);
            const db = parseModelDate(b.date_time);
            if (!da || !db) return 0;
            return da - db;
          });

          return (
            <Card key={photo._id} variant="outlined">
              <CardMedia
                component="img"
                image={src}
                alt={photo.file_name}
                sx={{ maxHeight: 480, objectFit: "contain", bgcolor: "action.hover" }}
              />
              <CardContent>
                <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                  {formatFriendlyDateTime(photo.date_time)}
                </Typography>
                <Divider sx={{ my: 2 }} />
                <Typography variant="subtitle1" gutterBottom>
                  Comments
                </Typography>
                {comments.length === 0 ? (
                  <Typography variant="body2" color="text.secondary">
                    No comments.
                  </Typography>
                ) : (
                  <Stack spacing={2} divider={<Divider flexItem />}>
                    {comments.map((c) => {
                      const commenter = c.user;
                      const commenterName = commenter
                        ? `${commenter.first_name} ${commenter.last_name}`
                        : "Unknown user";
                      const commenterId = commenter?._id;

                      return (
                        <Box key={c._id}>
                          <Typography variant="caption" color="text.secondary" display="block">
                            {formatFriendlyDateTime(c.date_time)}
                          </Typography>
                          {commenterId ? (
                            <Link
                              component={RouterLink}
                              to={`/users/${commenterId}`}
                              variant="subtitle2"
                              underline="hover"
                            >
                              {commenterName}
                            </Link>
                          ) : (
                            <Typography variant="subtitle2">{commenterName}</Typography>
                          )}
                          <Typography variant="body2" sx={{ mt: 0.5 }}>
                            {c.comment}
                          </Typography>
                        </Box>
                      );
                    })}
                  </Stack>
                )}
              </CardContent>
            </Card>
          );
        })
      )}
    </Stack>
  );
}

export default UserPhotos;
